options.helpers:
const handlebars = context.handlebars;

handlebars.registerHelper('equity_calendar', function(rows) {
  if (!rows || !rows.length) {
    return new handlebars.SafeString('<p style="color:#888;padding:16px">Sem dados no intervalo selecionado.</p>');
  }

  var dayMap = {};
  var minDay = null, maxDay = null;
  for (var i = 0; i < rows.length; i++) {
    var r = rows[i];
    var ds = r.day ? String(r.day).slice(0, 10) : null;
    if (!ds) continue;
    dayMap[ds] = { pct: parseFloat(r.pnl_pct || 0), usdt: parseFloat(r.pnl_usdt || 0) };
    if (!minDay || ds < minDay) minDay = ds;
    if (!maxDay || ds > maxDay) maxDay = ds;
  }

  function getColor(pct) {
    if (pct === null || pct === undefined) return 'rgba(255,255,255,0.04)';
    if (pct >  1.0) return '#1a7a1a';
    if (pct >  0.3) return '#2a8f2a';
    if (pct >  0.0) return '#4aab4a';
    if (pct === 0)  return 'rgba(255,255,255,0.06)';
    if (pct > -0.3) return '#ab4a4a';
    if (pct > -1.0) return '#8f2a2a';
    return '#7a1a1a';
  }

  var today = new Date();
  var mNames = ['Janeiro','Fevereiro','Março','Abril','Maio','Junho',
                'Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];

  function pad(n) { return String(n).padStart(2, '0'); }

  // Mês corrente do filtro
  var ey = parseInt(maxDay.slice(0, 4)), em = parseInt(maxDay.slice(5, 7)) - 1;
  var first    = new Date(ey, em, 1);
  var last     = new Date(ey, em + 1, 0);
  var startDow = first.getDay();

  var gridHtml = '<div style="display:grid;grid-template-columns:repeat(7,1fr);grid-auto-rows:1fr;gap:4px;flex:1">';
  // cabeçalho dias da semana
  ['Dom','Seg','Ter','Qua','Qui','Sex','Sáb'].forEach(function(lbl) {
    gridHtml += '<div style="text-align:center;color:#666;font-size:12px;font-weight:600;padding:4px 0">' + lbl + '</div>';
  });
  // células vazias antes do dia 1
  for (var e = 0; e < startDow; e++) {
    gridHtml += '<div></div>';
  }
  // dias
  for (var day = 1; day <= last.getDate(); day++) {
    var ds     = ey + '-' + pad(em + 1) + '-' + pad(day);
    var info   = dayMap[ds];
    var isToday = (today.getFullYear() === ey && today.getMonth() === em && today.getDate() === day);
    var bg     = info ? getColor(info.pct) : 'rgba(255,255,255,0.03)';
    var border = isToday ? '2px solid #ffd700' : '1px solid rgba(255,255,255,0.06)';
    var title  = info ? ds + ': ' + (info.pct >= 0 ? '+' : '') + info.pct.toFixed(3)
                     + '% ($' + (info.usdt >= 0 ? '+' : '') + info.usdt.toFixed(2) + ')' : ds;
    var pctStr = info ? (info.pct >= 0 ? '+' : '') + info.pct.toFixed(2) + '%' : '';
    var usdtStr = info ? (info.usdt >= 0 ? '+' : '') + info.usdt.toFixed(2) : '';
    gridHtml += '<div title="' + title + '" style="background:' + bg + ';border:' + border
      + ';border-radius:6px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:2px;cursor:default">'
      + '<span style="font-size:16px;color:rgba(255,255,255,' + (isToday ? '1' : '0.85') + ');font-weight:' + (isToday ? 700 : 400) + '">' + day + '</span>'
      + (info ? '<span style="font-size:12px;color:rgba(255,255,255,0.9);font-weight:600">' + pctStr + '</span>' : '')
      + (info ? '<span style="font-size:10px;color:rgba(255,255,255,0.6)">' + usdtStr + '</span>' : '')
      + '</div>';
  }
  gridHtml += '</div>';

  var legend = [
    ['#1a7a1a', '>+1%'], ['#2a8f2a', '+0.3–+1%'], ['#4aab4a', '0–+0.3%'],
    ['rgba(255,255,255,0.06)', 'sem dado'],
    ['#ab4a4a', '0–-0.3%'], ['#8f2a2a', '-0.3–-1%'], ['#7a1a1a', '<-1%']
  ].map(function(l) {
    return '<span style="background:' + l[0] + ';border-radius:4px;padding:3px 10px;color:rgba(255,255,255,0.9);font-size:12px">' + l[1] + '</span>';
  }).join('');

  return new handlebars.SafeString(
    '<div style="padding:12px 16px;font-family:Inter,sans-serif;width:100%;height:100%;box-sizing:border-box;display:flex;flex-direction:column;gap:8px">'
    + '<div>'
    +   '<div style="font-size:15px;font-weight:700;color:#FF9830">📅 PnL Diário — Equity vs Exchange</div>'
    +   '<div style="color:#8e8ea0;font-size:11px">Variação patrimônio total (USDT livre + BTC a mercado)</div>'
    + '</div>'
    + '<div style="font-size:20px;font-weight:700;color:#e0e0e0;text-align:center">' + mNames[em] + ' ' + ey + '</div>'
    + gridHtml
    + '<div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;padding-top:4px">'
    +   '<span style="color:#8e8ea0;font-size:11px">Legenda:</span>' + legend
    + '</div>'
    + '</div>'
  );
});
